import asyncio
from llama_index.core.workflow import (
    Workflow,
    StartEvent,
    StopEvent,
    step,
    Event,
)
from llama_index.llms.openai import OpenAI

class ProcessedEvent(Event):
    text: str

class SimpleWorkflow(Workflow):
    @step
    async def preprocess(self, ctx, ev: StartEvent) -> ProcessedEvent:
        # Trim and normalise the incoming query
        return ProcessedEvent(text=ev.query.strip().lower())

    @step
    async def answer(self, ctx, ev: ProcessedEvent) -> StopEvent:
        llm = OpenAI(model="gpt-4o-mini")
        response = await llm.acomplete(ev.text)
        return StopEvent(result=str(response))

async def main():
    wf = SimpleWorkflow(timeout=60, verbose=False)
    result = await wf.run(query="What is LlamaIndex?")
    print(result)

asyncio.run(main())

from llama_index.core.workflow import (
    Workflow, StartEvent, StopEvent, step, Event
)

class WebEvent(Event):
    content: str

class DBEvent(Event):
    content: str

class ParallelWorkflow(Workflow):
    @step
    async def fetch_web(self, ctx, ev: StartEvent) -> WebEvent:
        # runs in parallel with fetch_db
        return WebEvent(content=f"Web result for: {ev.query}")

    @step
    async def fetch_db(self, ctx, ev: StartEvent) -> DBEvent:
        # runs in parallel with fetch_web
        return DBEvent(content=f"DB result for: {ev.query}")

    @step
    async def merge(self, ctx, ev: WebEvent | DBEvent) -> StopEvent:
        # This step is called ONCE PER event — not once per pair.
        # Use ctx to accumulate results:
        results = ctx.collect_events(ev, [WebEvent, DBEvent])
        if results is None:
            return None   # wait for both events
        web_ev, db_ev = results
        combined = f"{web_ev.content}
{db_ev.content}"
        return StopEvent(result=combined)

