class StepAEvent(Event):
    pass

class ContextWorkflow(Workflow):
    @step
    async def step_a(self, ctx: Context, ev: StartEvent) -> StepAEvent:
        # Store large objects in context rather than events
        await ctx.set("index", ev.index)
        await ctx.set("llm", ev.llm)
        return StepAEvent()

    @step
    async def step_b(self, ctx: Context, ev: StepAEvent) -> StopEvent:
        index = await ctx.get("index")
        llm = await ctx.get("llm")
        # use index and llm here
        return StopEvent(result="done")

