import asyncio
from llama_index.core.workflow import Workflow, StartEvent, StopEvent, step, Event

class FetchEvent(Event):
    url: str

class FetchResultEvent(Event):
    content: str

class RetryWorkflow(Workflow):
    @step
    async def fetch(self, ctx, ev: StartEvent) -> FetchResultEvent:
        url = ev.url
        max_attempts = 3
        for attempt in range(max_attempts):
            try:
                # Replace with real HTTP call
                content = f"content from {url}"
                return FetchResultEvent(content=content)
            except Exception as e:
                if attempt == max_attempts - 1:
                    raise
                wait = 2 ** attempt   # exponential backoff: 1s, 2s, 4s
                await asyncio.sleep(wait)

    @step
    async def process(self, ctx, ev: FetchResultEvent) -> StopEvent:
        return StopEvent(result=ev.content.upper())

from llama_index.core.workflow import Workflow, StartEvent, StopEvent, step, Event

class SimpleQueryEvent(Event):
    query: str

class ComplexQueryEvent(Event):
    query: str

class RouterWorkflow(Workflow):
    @step
    async def classify(
        self, ctx, ev: StartEvent
    ) -> SimpleQueryEvent | ComplexQueryEvent:
        # Use a fast heuristic or a small model to classify
        if len(ev.query.split()) < 10:
            return SimpleQueryEvent(query=ev.query)
        return ComplexQueryEvent(query=ev.query)

    @step
    async def handle_simple(self, ctx, ev: SimpleQueryEvent) -> StopEvent:
        return StopEvent(result=f"Simple answer to: {ev.query}")

    @step
    async def handle_complex(self, ctx, ev: ComplexQueryEvent) -> StopEvent:
        # invoke a deeper pipeline here
        return StopEvent(result=f"Complex answer to: {ev.query}")

from llama_index.core.workflow import Workflow, StartEvent, StopEvent, step, Event, Context

class DraftEvent(Event):
    draft: str
    iteration: int

class IterativeWorkflow(Workflow):
    MAX_ITERATIONS = 3

    @step
    async def start(self, ctx: Context, ev: StartEvent) -> DraftEvent:
        return DraftEvent(draft="Initial draft.", iteration=0)

    @step
    async def refine(self, ctx: Context, ev: DraftEvent) -> DraftEvent | StopEvent:
        if ev.iteration >= self.MAX_ITERATIONS:
            return StopEvent(result=ev.draft)
        refined = f"{ev.draft} [refined round {ev.iteration + 1}]"
        return DraftEvent(draft=refined, iteration=ev.iteration + 1)
